const express = require('express');
const http = require('http');
const session = require('express-session');
const { Server } = require('socket.io');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);

const sessionMiddleware = session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    httpOnly: true,
    sameSite: 'lax',
    secure: process.env.NODE_ENV === 'production',
    maxAge: 1000 * 60 * 60 * 24
  }
});

app.use(express.json({ limit: '16kb' }));
app.use(sessionMiddleware);

const io = new Server(server, {
  cors: {
    origin: process.env.CORS_ORIGIN ? process.env.CORS_ORIGIN.split(',') : true,
    credentials: true
  }
});

io.engine.use(sessionMiddleware);

const players = new Map();
const socketsByPlayerId = new Map();

function generateId() {
  return crypto.randomUUID ? crypto.randomUUID() : crypto.randomBytes(16).toString('hex');
}

function sanitizeUsername(username) {
  if (typeof username !== 'string') return null;
  const trimmed = username.trim();
  if (trimmed.length < 3 || trimmed.length > 20) return null;
  if (!/^[a-zA-Z0-9_ -]+$/.test(trimmed)) return null;
  return trimmed;
}

function clampScore(score) {
  const n = Number(score);
  if (!Number.isFinite(n)) return null;
  return Math.max(0, Math.floor(n));
}

function requireAuth(req, res, next) {
  if (!req.session.playerId || !players.has(req.session.playerId)) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
}

function leaderboard() {
  return [...players.values()]
    .map(p => ({
      id: p.id,
      username: p.username,
      score: p.score,
      connected: p.connected
    }))
    .sort((a, b) => b.score - a.score)
    .slice(0, 100);
}

app.post('/auth/login', (req, res) => {
  const username = sanitizeUsername(req.body?.username);
  if (!username) {
    return res.status(400).json({ error: 'Invalid username' });
  }

  let existing = [...players.values()].find(p => p.username.toLowerCase() === username.toLowerCase());
  if (!existing) {
    existing = {
      id: generateId(),
      username,
      score: 0,
      connected: false,
      createdAt: Date.now(),
      lastSeenAt: Date.now()
    };
    players.set(existing.id, existing);
  } else {
    existing.lastSeenAt = Date.now();
  }

  req.session.playerId = existing.id;
  req.session.username = existing.username;

  req.session.save(err => {
    if (err) {
      return res.status(500).json({ error: 'Session error' });
    }
    res.json({
      ok: true,
      player: {
        id: existing.id,
        username: existing.username,
        score: existing.score
      }
    });
  });
});

app.post('/auth/logout', requireAuth, (req, res) => {
  const playerId = req.session.playerId;
  const player = players.get(playerId);
  if (player) {
    player.connected = false;
    player.lastSeenAt = Date.now();
  }

  const set = socketsByPlayerId.get(playerId);
  if (set) {
    for (const socketId of set) {
      const socket = io.sockets.sockets.get(socketId);
      if (socket) socket.disconnect(true);
    }
    socketsByPlayerId.delete(playerId);
  }

  req.session.destroy(() => {
    res.json({ ok: true });
    io.emit('leaderboard:update', leaderboard());
  });
});

app.get('/auth/me', requireAuth, (req, res) => {
  const player = players.get(req.session.playerId);
  res.json({
    ok: true,
    player: {
      id: player.id,
      username: player.username,
      score: player.score,
      connected: player.connected
    }
  });
});

app.get('/leaderboard', (_req, res) => {
  res.json({ ok: true, leaderboard: leaderboard() });
});

io.on('connection', socket => {
  const req = socket.request;
  const playerId = req.session?.playerId;

  if (!playerId || !players.has(playerId)) {
    socket.emit('error:auth', { error: 'Unauthorized socket' });
    socket.disconnect(true);
    return;
  }

  const player = players.get(playerId);
  player.connected = true;
  player.lastSeenAt = Date.now();

  if (!socketsByPlayerId.has(playerId)) {
    socketsByPlayerId.set(playerId, new Set());
  }
  socketsByPlayerId.get(playerId).add(socket.id);

  socket.emit('player:init', {
    id: player.id,
    username: player.username,
    score: player.score
  });

  io.emit('leaderboard:update', leaderboard());

  socket.on('player:updateScore', payload => {
    const currentPlayer = players.get(playerId);
    if (!currentPlayer) return;

    const score = clampScore(payload?.score);
    if (score === null) {
      socket.emit('error:score', { error: 'Invalid score' });
      return;
    }

    currentPlayer.score = score;
    currentPlayer.lastSeenAt = Date.now();

    io.emit('leaderboard:update', leaderboard());
    socket.emit('player:scoreUpdated', { score: currentPlayer.score });
  });

  socket.on('player:heartbeat', () => {
    const currentPlayer = players.get(playerId);
    if (!currentPlayer) return;
    currentPlayer.lastSeenAt = Date.now();
  });

  socket.on('disconnect', () => {
    const currentPlayer = players.get(playerId);
    const set = socketsByPlayerId.get(playerId);

    if (set) {
      set.delete(socket.id);
      if (set.size === 0) {
        socketsByPlayerId.delete(playerId);
        if (currentPlayer) {
          currentPlayer.connected = false;
          currentPlayer.lastSeenAt = Date.now();
        }
      }
    }

    io.emit('leaderboard:update', leaderboard());
  });
});

const PORT = Number(process.env.PORT) || 3000;
server.listen(PORT, () => {
  console.log(`Game server listening on port ${PORT}`);
});